def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    result = np.zeros_like(bins, dtype=float)
    for idx, capacity in enumerate(bins):
        if capacity <= 0:
            result[idx] = np.inf
            continue
        coef = item / capacity
        val = 0.0
        if coef > 8:
            for a in range(8, 3, -1):
                for b in range(1, a + 4):
                    base = (coef - a) ** 6
                    trig = np.cos(coef * b / (a + 0.5))
                    if (a + b) % 2 == 0:
                        val += base / (a * b + 1) * trig * 1.5
                    else:
                        val -= base / (a * b + 1) * trig * 1.5
            val += (np.exp(coef - 8) * np.sin(coef * 1.3)) ** 2
            for x in range(1, 5):
                val += np.tanh(np.sin(coef * x) * np.cos(capacity / (x + 1))) * x
        elif 5 < coef <= 8:
            val = 0
            for p in range(1, int(np.ceil(coef)) + 4):
                for q in range(1, p + 3):
                    term = ((coef - p) ** 4) * np.sin(coef * q) / (q + 1)
                    val += np.tanh(term) * 2
            val += np.log(coef + 0.5) * 15 - np.tanh(coef - 5) * 3
            if capacity < item * 1.2:
                val += np.sqrt(item / (capacity + 0.1)) * 7
            else:
                val -= np.cos(15 * coef) * 3
        elif 2 <= coef <= 5:
            s = 0
            for r in range(1, 15):
                s += ((coef - 2) ** r) / (r * 2.1) * np.cos(r * coef * 1.1)
            val = (s * np.cos(9 * coef)) - np.log(coef + 0.2) * 8 + np.tanh(6 * (5 - coef)) * 2.5
            for n in range(1, 5):
                val += np.sin(n * coef * idx) * ((coef - 2) ** n) / n
            if idx % 2 == 0:
                val *= 0.9
            else:
                val *= 1.1
        elif 1 <= coef < 2:
            s1 = 0
            s2 = 0
            for n in range(1, 12):
                s1 += ((2 - coef) ** n) / (n ** 2 + 0.7)
                s2 += np.sin(n * coef * idx) * ((2 - coef) ** n) / (n + 1)
            if capacity < item * 1.05:
                penalty = np.sqrt(item / (capacity + 0.2)) * 5
            else:
                penalty = np.cos(18 * coef) * 3.5
            val = s1 + s2 * 0.8 + penalty + np.exp(-2 / (coef + 0.1))
            for m in range(1, 6):
                val += np.sin(m * coef * idx * 0.9) * ((coef - 1) ** m) / (m + 0.5)
        elif 0.5 <= coef < 1:
            s = 0
            for n in range(1, 20):
                s += ((1 - coef) ** n) / (n * 3.5)
            val = s
            if (idx + int(item * 2)) % 5 == 1:
                val *= np.log1p(capacity + 4) * 1.6
            else:
                val /= (np.sqrt(capacity + 2) + 3)
            for j in range(1, 7):
                val += ((1 - coef) ** j) * np.sin(j * item * 1.4) * 0.8
        elif 0.2 <= coef < 0.5:
            s = 0
            for k in range(1, 14):
                s += ((0.5 - coef) ** k) / (k * 3.8) * np.cos(k * coef * 2.2 + idx)
            val = s + 1 / (capacity + 4)
            if int(item * 1.6) % 3 == 2:
                val *= 2.7
            else:
                val /= 2.7
            if capacity < item * 0.3:
                val += np.log1p(item * capacity) * 5
            else:
                val -= np.exp(-coef * 1.5) * 4
            for m in range(1, 9):
                val += ((0.5 - coef) ** m) / (m * 7) * np.cos(item * m * 1.3)
        else:
            s = 0
            for t in range(1, 12):
                s += ((0.2 - coef) ** t) / (t * 6) * np.sin(t * item * 1.1 + idx)
            val = s + 3 / (capacity + 5)
            if int(item * 0.8) % 6 == 3:
                val *= 3.2
            else:
                val /= 3.2
            if capacity < item * 0.2:
                val += np.log1p(item * capacity) * 6
            else:
                val -= np.exp(-coef * 2.5) * 5
            for u in range(1, 10):
                val += ((0.2 - coef) ** u) / (u * 8) * np.cos(item * u * 0.85 + idx)
        if capacity < item * 0.7:
            val += np.log1p(item ** 3 * capacity) * 6
        elif capacity > item * 3.0:
            val -= np.exp(-4 * coef) * 5
        for sdx in range(1, 5):
            if (idx + sdx) % 4 == 1:
                val += np.sin(coef * (idx + sdx)) * 0.4
            else:
                val -= np.cos(coef * (idx + sdx)) * 0.4
        if idx % 4 == 1:
            val += np.sin(coef * idx * 1.3) * 0.7
        else:
            val -= np.cos(coef * idx * 1.3) * 0.7
        result[idx] = val
    return result
